#include <bits/stdc++.h>
using namespace std;
void f(int ans,int n){
    if(ans==0)return;
    f(ans/n,n);
    if(ans%n>9)cout<<char((ans%n)-10+'A');
    else cout<<char(ans%n+'0');
}
int main(){
    int n,m,ans=0;
    string s;
    cin>>n>>s>>m;
    for(int i=0;i<s.size();i++){
    	int tmp;
        if(s[i]>='0' && s[i]<='9')tmp=s[i]-'0';
        else tmp=s[i]-'A'+10;
        ans+=tmp*pow(n,s.size()-i-1);
    }
    f(ans,m);
    return 0;
}
